import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";
import { addSale } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function AddSale() {
  const navigate = useNavigate();
  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [vehicles, setVehicles] = useState([]);
  const [leads, setLeads] = useState([]);

  const [form, setForm] = useState({
    vehicle: "",
    customer: "",
    price: "",
    payment_status: "pending",
  });

  const [error, setError] = useState("");

  useEffect(() => {
    if (!canManage) {
      alert("Access denied");
      navigate("/vehicles");
      return;
    }

    const load = async () => {
      setError("");
      setLoading(true);
      try {
        const [vRes, lRes] = await Promise.all([api.get("/vehicles"), api.get("/leads")]);

        const availableVehicles = (vRes.data || []).filter((v) => v.status === "available");
        const leadList = lRes.data || [];

        setVehicles(availableVehicles);
        setLeads(leadList);

        setForm((prev) => ({
          ...prev,
          vehicle: availableVehicles[0]?._id || "",
          customer: leadList[0]?._id || "",
        }));
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load vehicles/leads");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [canManage, navigate]);

  const selectedVehicle = useMemo(
    () => vehicles.find((v) => v._id === form.vehicle),
    [vehicles, form.vehicle]
  );

  const selectedLead = useMemo(
    () => leads.find((l) => l._id === form.customer),
    [leads, form.customer]
  );

  const onChange = (e) => {
    const { name, value } = e.target;
    setForm((p) => ({ ...p, [name]: value }));
  };

  const submit = async (e) => {
    e.preventDefault();
    setError("");

    if (!form.vehicle) return setError("Please select a vehicle");
    if (!form.customer) return setError("Please select a customer (lead)");
    if (form.price === "" || Number(form.price) < 0) return setError("Price must be 0 or more");

    setSaving(true);
    try {
      await addSale({
        vehicle: form.vehicle,
        customer: form.customer,
        price: Number(form.price),
        payment_status: form.payment_status,
      });

      alert("Sale saved successfully!");
      navigate("/sales");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to save sale");
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <p style={{ padding: 20 }}>Loading...</p>;

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Add Sale</div>
          <div className="pageSub">Create a new sale record (Admin/Manager only)</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 720, margin: "32px auto" }}>
        {error && (
          <div style={{ marginBottom: 16, padding: 12, borderRadius: "var(--radius)", border: "1px solid var(--danger)", backgroundColor: "rgba(244, 67, 54, 0.1)", color: "var(--danger)" }}>
            <b>Error:</b> {error}
          </div>
        )}

        <form onSubmit={submit}>
          <label className="label">Vehicle</label>
          <select
            className="select"
            name="vehicle"
            value={form.vehicle}
            onChange={onChange}
            required
            style={{ marginBottom: 16 }}
            disabled={vehicles.length === 0}
          >
            {vehicles.length === 0 ? (
              <option value="">No available vehicles</option>
            ) : (
              vehicles.map((v) => (
                <option key={v._id} value={v._id}>
                  {v.brand} {v.model || v.type || ""} ({v.year}) — {v.status}
                </option>
              ))
            )}
          </select>
          {selectedVehicle && (
            <div style={{ marginBottom: 16, paddingBottom: 12, borderBottom: "1px solid var(--border)", fontSize: 13, opacity: 0.75 }}>
              Selected: <b>{selectedVehicle.brand}</b> {selectedVehicle.model || selectedVehicle.type || ""} — Rs. {" "}
              {Number(selectedVehicle.price || 0).toLocaleString()}
            </div>
          )}

          <label className="label">Customer (Lead)</label>
          <select
            className="select"
            name="customer"
            value={form.customer}
            onChange={onChange}
            required
            style={{ marginBottom: 16 }}
            disabled={leads.length === 0}
          >
            {leads.length === 0 ? (
              <option value="">No leads</option>
            ) : (
              leads.map((l) => (
                <option key={l._id} value={l._id}>
                  {l.name} — {l.contact_number || "-"}
                </option>
              ))
            )}
          </select>
          {selectedLead && (
            <div style={{ marginBottom: 16, paddingBottom: 12, borderBottom: "1px solid var(--border)", fontSize: 13, opacity: 0.75 }}>
              Selected: <b>{selectedLead.name}</b> {selectedLead.email ? `(${selectedLead.email})` : ""}
            </div>
          )}

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
            <div>
              <label className="label">Price (Rs.)</label>
              <input
                className="input"
                name="price"
                type="number"
                min="0"
                value={form.price}
                onChange={onChange}
                required
                placeholder="e.g. 5500000"
              />
            </div>

            <div>
              <label className="label">Payment Status</label>
              <select
                className="select"
                name="payment_status"
                value={form.payment_status}
                onChange={onChange}
              >
                <option value="pending">Pending</option>
                <option value="partial">Partial</option>
                <option value="completed">Completed</option>
              </select>
            </div>
          </div>

          <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
            <button type="submit" className="btn btnPrimary" disabled={saving || vehicles.length === 0}>
              {saving ? "Saving..." : "Save Sale"}
            </button>
            <button type="button" className="btn" onClick={() => navigate("/sales")} disabled={saving}>
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
